import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Layout.css';

function Layout({ children }) {
  const navigate = useNavigate();
  const [userName, setUserName] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  useEffect(() => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    const fetchUserData = async () => {
      try {
        const response = await fetch(`http://localhost:5000/api/user/${user_id}`);
        const data = await response.json();
        if (data.name) {
          setUserName(data.name);
        }
      } catch (error) {
        console.error('Error fetching user data:', error);
      }
    };

    fetchUserData();
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`layout-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>Home</button>
          <button onClick={() => navigate('/recording-indicators')}>Recording Indicators</button>
          <button onClick={() => navigate('/exacerbation-forecast')}>Exacerbation Forecast</button>
          <button onClick={() => navigate('/graphs-of-changes')}>Graphs of Changes</button>
          <button onClick={() => navigate('/medication-diary')}>Medication Diary</button>
        </nav>
      </div>

      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
      <div className="page-content">
        {children}
        </div>
    </div>
  );
}

export default Layout;
